+      return registration.handler({
+        ...handlerContext,
+        channel: "telegram",
+        callback: {
+          data: params.data,
+          namespace,
+          payload,
+          messageId: callbackMessage.messageId,
+          chatId: callbackMessage.chatId,
+          messageText: callbackMessage.messageText,
